package com.socialblog.interaction.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;@Entity @Table(name="target_projection")public class TargetProjection{@EmbeddedId private TargetKey id;@Column(nullable=false)private boolean active;@Column(name="owner_id")private UUID ownerId;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected TargetProjection(){}public TargetProjection(TargetKey id,boolean value){this(id,value,null);}public TargetProjection(TargetKey id,boolean value,UUID owner){this.id=id;update(value,owner);}public void update(boolean value,UUID owner){active=value;if(owner!=null)ownerId=owner;updatedAt=Instant.now();}public void setActive(boolean value){update(value,null);}public boolean isActive(){return active;}public TargetKey getId(){return id;}public UUID getOwnerId(){return ownerId;}}
